#include<bits/stdc++.h>
using namespace std;
struct node {
	int ss,ee;
} a[1000005];
int n,ans=999999999;
bool cmp(node a,node b) {
	return a.ee>b.ee;
}
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1; i<=n; i++) {
		cin>>a[i].ss>>a[i].ee;
	}
	sort(a+1,a+n+1,cmp);
	for(int i=1; i<=n; i++) {
		ans=min(ans,a[i].ee)-a[i].ss;
	}
	if(ans<0) {
		ans=-1;
	}
	cout<<ans;
	return 0;
}
